# Some older SHAP versions use NumPy aliases removed from
# recent NumPy releases. These aliases are restored only for
# package compatibility and do not change the analysis.
if not hasattr(np, "bool"):
    np.bool = bool

if not hasattr(np, "int"):
    np.int = int

if not hasattr(np, "float"):
    np.float = float


# ============================================================
# 2. Analysis settings
# ============================================================

RANDOM_STATE = 42

# Pseudocount used in the original model target and shallow-RA
# log transformation.
PSEUDOCOUNT = 1e-8

# Number of independent test-set OTU rows used for SHAP.
# Increase this later if a larger explanation sample is required.
N_SHAP_ROWS = 300

# OTHER is a pooled residual component rather than one specific OTU.
# It is therefore excluded from the main SHAP interpretation.
EXCLUDE_OTHER = True


# ============================================================
# 3. Model feature columns
#
# Names and order must exactly match those used during training.
# ============================================================

