def require_file(file_path: Path) -> None:
    """Raise a clear error if a required input file is missing."""

    if not file_path.exists():
        raise FileNotFoundError(
            f"Required file not found:\n{file_path}\n\n"
            "Check that the earlier analysis script completed successfully."
        )


def assign_abundance_group(
    target_ra: pd.Series,
) -> pd.Series:
    """
    Assign reference-abundance strata.

    Dominant:
        reference RA >= 1e-2

    Common:
        1e-3 <= reference RA < 1e-2

    Rare:
        1e-4 <= reference RA < 1e-3

    Very rare:
        0 < reference RA < 1e-4

    Reference zero:
        reference RA == 0
    """

    target_ra = pd.to_numeric(
        target_ra,
        errors="coerce",
    ).fillna(0.0)

    conditions = [
        target_ra >= 1e-2,
        (
            (target_ra >= 1e-3)
            & (target_ra < 1e-2)
        ),
        (
            (target_ra >= 1e-4)
            & (target_ra < 1e-3)
        ),
        (
            (target_ra > 0)
            & (target_ra < 1e-4)
        ),
        target_ra == 0,
    ]

    choices = [
        "Dominant (>=1e-2)",
        "Common (1e-3 to 1e-2)",
        "Rare (1e-4 to 1e-3)",
        "Very rare (<1e-4)",
        "Reference zero",
    ]

    return pd.Series(
        np.select(
            conditions,
            choices,
            default="Unknown",
        ),
        index=target_ra.index,
    )


def rebuild_derived_features(
    data: pd.DataFrame,
) -> list[str]:
    """
    Rebuild deterministic model features if they were not retained
    in an older prediction output file.

    These variables are reconstructed only from columns already
    present in the test prediction table.
    """

    rebuilt_features = []

    # log(1 + shallow count)
    if (
        "log1p_shallow_count" not in data.columns
        and "shallow_count" in data.columns
    ):
        shallow_count = pd.to_numeric(
            data["shallow_count"],
            errors="coerce",
        ).fillna(0.0)

        shallow_count = shallow_count.clip(
            lower=0.0
        )

        data["log1p_shallow_count"] = np.log1p(
            shallow_count
        )

        rebuilt_features.append(
            "log1p_shallow_count"
        )

    # log10(shallow RA + pseudocount)
    if (
        "log10_shallow_ra" not in data.columns
        and "shallow_ra" in data.columns
    ):
        shallow_ra = pd.to_numeric(
            data["shallow_ra"],
            errors="coerce",
        ).fillna(0.0)

        shallow_ra = shallow_ra.clip(
            lower=0.0
        )

        data["log10_shallow_ra"] = np.log10(
            shallow_ra + PSEUDOCOUNT
        )

        rebuilt_features.append(
            "log10_shallow_ra"
        )

    # Binary shallow-zero indicator
    if (
        "zero_in_shallow" not in data.columns
        and "shallow_count" in data.columns
    ):
        shallow_count = pd.to_numeric(
            data["shallow_count"],
            errors="coerce",
        ).fillna(0.0)

        data["zero_in_shallow"] = (
            shallow_count <= 0
        ).astype(np.int8)

        rebuilt_features.append(
            "zero_in_shallow"
        )

    # Normalised shallow abundance rank
    if (
        "shallow_rank_norm" not in data.columns
        and {
            "shallow_rank",
            "shallow_richness",
        }.issubset(data.columns)
    ):
        shallow_rank = pd.to_numeric(
            data["shallow_rank"],
            errors="coerce",
        ).fillna(0.0)

        shallow_richness = pd.to_numeric(
            data["shallow_richness"],
            errors="coerce",
        ).fillna(0.0)

        denominator = (
            shallow_richness + 1.0
        ).replace(
            0.0,
            1.0,
        )

        data["shallow_rank_norm"] = (
            shallow_rank
            / denominator
        )

        rebuilt_features.append(
            "shallow_rank_norm"
        )

    # Indicator for the pooled OTHER component
    if (
        "is_other" not in data.columns
        and "otu_id" in data.columns
    ):
        data["is_other"] = (
            data["otu_id"]
            .astype(str)
            .eq("OTHER")
            .astype(np.int8)
        )

        rebuilt_features.append(
            "is_other"
        )

    return rebuilt_features


def validate_model_features(
    data: pd.DataFrame,
) -> None:
    """Check that all model features exist and contain finite values."""

    missing_features = sorted(
        set(FEATURE_COLUMNS)
        - set(data.columns)
    )

    if missing_features:
        raise ValueError(
            "The test prediction table is missing model features "
            "that cannot be rebuilt:\n"
            f"{missing_features}"
        )

    feature_check = (
        data[FEATURE_COLUMNS]
        .replace(
            [np.inf, -np.inf],
            np.nan,
        )
    )

    if feature_check.isna().any().any():
        missing_counts = (
            feature_check
            .isna()
            .sum()
        )

        missing_counts = missing_counts.loc[
            missing_counts > 0
        ]

        raise ValueError(
            "Some model features contain missing or infinite values:\n"
            f"{missing_counts.to_string()}"
        )


def validate_metadata(
    data: pd.DataFrame,
) -> None:
    """Check metadata columns required for downstream SHAP analysis."""

    required_columns = [
        "sample_id",
        "subsample_repeat",
        "otu_id",
        "shallow_depth",
        "shallow_count",
        "shallow_ra",
        "zero_in_shallow",
        "target_reference_ra",
        "target_log10_reference_ra",
        "pred_raw_shallow_ra",
        "pred_random_forest_ra",
        "pred_xgboost_ra",
        "is_other",
    ]

    missing_columns = sorted(
        set(required_columns)
        - set(data.columns)
    )

    if missing_columns:
        raise ValueError(
            "The test prediction table is missing required "
            "metadata or prediction columns:\n"
            f"{missing_columns}"
        )


def extract_rf_shap_values(
    model,
    X: pd.DataFrame,
) -> tuple[np.ndarray, np.ndarray]:
    """
    Compute Random Forest SHAP values with TreeExplainer.

    Returns:
        shap_values:
            Array of shape n_rows x n_features.

        base_values:
            One base value per row.
    """

    explainer = shap.TreeExplainer(
        model
    )

    explanation = None

    try:
        explanation = explainer(
            X,
            check_additivity=False,
        )

    except TypeError:
        try:
            explanation = explainer(X)

        except Exception:
            explanation = None

    if (
        explanation is not None
        and hasattr(explanation, "values")
    ):
        shap_values = np.asarray(
            explanation.values
        )

        base_values = np.asarray(
            explanation.base_values
        )

    else:
        shap_values = explainer.shap_values(
            X,
            check_additivity=False,
        )

        if isinstance(
            shap_values,
            list,
        ):
            shap_values = shap_values[0]

        shap_values = np.asarray(
            shap_values
        )

        expected_value = (
            explainer.expected_value
        )

        if isinstance(
            expected_value,
            (list, tuple, np.ndarray),
        ):
            expected_value = (
                np.asarray(expected_value)
                .reshape(-1)[0]
            )

        base_values = np.repeat(
            float(expected_value),
            len(X),
        )

    # Remove an unnecessary single-output dimension if present.
    if shap_values.ndim == 3:
        if shap_values.shape[-1] == 1:
            shap_values = (
                shap_values[:, :, 0]
            )

        elif shap_values.shape[0] == 1:
            shap_values = shap_values[0]

    if shap_values.ndim != 2:
        raise ValueError(
            "Unexpected Random Forest SHAP shape: "
            f"{shap_values.shape}"
        )

    base_values = np.asarray(
        base_values
    )

    if base_values.ndim == 0:
        base_values = np.repeat(
            float(base_values),
            len(X),
        )

    elif base_values.ndim >= 2:
        base_values = (
            base_values
            .reshape(len(X), -1)[:, 0]
        )

    elif len(base_values) == 1:
        base_values = np.repeat(
            float(base_values[0]),
            len(X),
        )

    if len(base_values) != len(X):
        raise ValueError(
            "Unexpected Random Forest base-value length: "
            f"{len(base_values)}; expected {len(X)}."
        )

    return (
        shap_values.astype(np.float64),
        base_values.astype(np.float64),
    )


def extract_xgb_shap_values(
    model,
    X: pd.DataFrame,
) -> tuple[np.ndarray, np.ndarray]:
    """
    Compute XGBoost SHAP values using the native pred_contribs API.

    The final returned contribution column is the base value.
    All preceding columns are feature-specific SHAP values.
    """

    booster = model.get_booster()

    dmatrix = xgb.DMatrix(
        X,
        feature_names=list(X.columns),
    )

    contributions = booster.predict(
        dmatrix,
        pred_contribs=True,
        approx_contribs=False,
    )

    contributions = np.asarray(
        contributions,
        dtype=np.float64,
    )

    expected_columns = (
        X.shape[1] + 1
    )

    if (
        contributions.ndim != 2
        or contributions.shape[1]
        != expected_columns
    ):
        raise ValueError(
            "Unexpected XGBoost SHAP shape: "
            f"{contributions.shape}. "
            f"Expected {expected_columns} columns."
        )

    shap_values = (
        contributions[:, :-1]
    )

    base_values = (
        contributions[:, -1]
    )

    return (
        shap_values,
        base_values,
    )


def build_shap_table(
    metadata: pd.DataFrame,
    X: pd.DataFrame,
    shap_values: np.ndarray,
    base_values: np.ndarray,
    model_name: str,
) -> pd.DataFrame:
    """
    Combine metadata, feature values and per-feature SHAP values
    into one row-level output table.
    """

    output = (
        metadata
        .reset_index(drop=True)
        .copy()
    )

    X_reset = (
        X
        .reset_index(drop=True)
        .copy()
    )

    for feature in FEATURE_COLUMNS:
        output[feature] = (
            X_reset[feature]
        )

    for feature_index, feature in enumerate(
        FEATURE_COLUMNS
    ):
        output[
            f"SHAP__{feature}"
        ] = shap_values[
            :,
            feature_index,
        ]

    output["SHAP_base_value"] = (
        base_values
    )

    output["SHAP_sum"] = (
        shap_values.sum(axis=1)
    )

    output[
        "SHAP_reconstructed_log_prediction"
    ] = (
        output["SHAP_base_value"]
        + output["SHAP_sum"]
    )

    output["model"] = model_name

    return output


def calculate_additivity_check(
    rf_model,
    xgb_model,
    X: pd.DataFrame,
    rf_shap_values: np.ndarray,
    rf_base_values: np.ndarray,
    xgb_shap_values: np.ndarray,
    xgb_base_values: np.ndarray,
) -> pd.DataFrame:
    """
    Check whether:

        base value + sum of SHAP values

    reproduces the original model output on the log10 scale.
    """

    rf_prediction = np.asarray(
        rf_model.predict(X),
        dtype=np.float64,
    )

    xgb_prediction = np.asarray(
        xgb_model.predict(X),
        dtype=np.float64,
    )

    rf_reconstructed = (
        rf_base_values
        + rf_shap_values.sum(axis=1)
    )

    xgb_reconstructed = (
        xgb_base_values
        + xgb_shap_values.sum(axis=1)
    )

    rf_error = np.abs(
        rf_prediction
        - rf_reconstructed
    )

    xgb_error = np.abs(
        xgb_prediction
        - xgb_reconstructed
    )

    return pd.DataFrame(
        {
            "model": [
                "Random Forest",
                "XGBoost",
            ],
            "mean_absolute_additivity_error": [
                float(
                    np.mean(rf_error)
                ),
                float(
                    np.mean(xgb_error)
                ),
            ],
            "max_absolute_additivity_error": [
                float(
                    np.max(rf_error)
                ),
                float(
                    np.max(xgb_error)
                ),
            ],
        }
    )


# ============================================================
# 7. Main analysis
# ============================================================

def main() -> None:
    """Prepare the SHAP sample and compute model explanations."""

    overall_start = time.time()

    # --------------------------------------------------------
    # Step 1: Read inputs
    # --------------------------------------------------------

    banner(
        "Step 1: Read trained models and test predictions"
    )

    require_file(
        RF_MODEL_FILE
    )

    require_file(
        XGB_MODEL_FILE
    )

    require_file(
        TEST_PREDICTION_FILE
    )

    rf_model = joblib.load(
        RF_MODEL_FILE
    )

    xgb_model = joblib.load(
        XGB_MODEL_FILE
    )

    test_data = pd.read_pickle(
        TEST_PREDICTION_FILE
    )

    print(
        f"Random Forest model:\n"
        f"  {RF_MODEL_FILE}"
    )

    print(
        f"XGBoost model:\n"
        f"  {XGB_MODEL_FILE}"
    )

    print(
        f"Test prediction file:\n"
        f"  {TEST_PREDICTION_FILE}"
    )

    print(
        "Test prediction table shape: "
        f"{test_data.shape}"
    )

    # --------------------------------------------------------
    # Step 2: Validate features and metadata
    # --------------------------------------------------------

    banner(
        "Step 2: Rebuild and validate model features"
    )

    rebuilt_features = (
        rebuild_derived_features(
            test_data
        )
    )

    if rebuilt_features:
        print(
            "Rebuilt derived features:"
        )

        for feature in rebuilt_features:
            print(
                f"  - {feature}"
            )

    else:
        print(
            "No derived features needed rebuilding."
        )

    validate_model_features(
        test_data
    )

    validate_metadata(
        test_data
    )

    print(
        "Feature validation passed: "
        f"{len(FEATURE_COLUMNS)} features"
    )

    # --------------------------------------------------------
    # Step 3: Prepare fixed SHAP sample
    # --------------------------------------------------------

    banner(
        "Step 3: Build the fixed SHAP test sample"
    )

    if EXCLUDE_OTHER:
        candidate_data = test_data.loc[
            test_data["is_other"] == 0
        ].copy()

    else:
        candidate_data = (
            test_data.copy()
        )

    candidate_data[
        "abundance_group"
    ] = assign_abundance_group(
        candidate_data[
            "target_reference_ra"
        ]
    )

    candidate_data[
        "shallow_detection_group"
    ] = np.where(
        candidate_data[
            "zero_in_shallow"
        ] == 1,
        "Shallow zero",
        "Detected in shallow",
    )

    if candidate_data.empty:
        raise ValueError(
            "No candidate rows are available "
            "for SHAP analysis."
        )

    n_shap_rows = min(
        N_SHAP_ROWS,
        len(candidate_data),
    )

    shap_sample = (
        candidate_data
        .sample(
            n=n_shap_rows,
            random_state=RANDOM_STATE,
            replace=False,
        )
        .reset_index(drop=True)
    )

    X_shap = (
        shap_sample[
            FEATURE_COLUMNS
        ]
        .astype(np.float32)
    )

    shap_metadata = (
        shap_sample[
            METADATA_COLUMNS
        ]
        .copy()
    )

    shap_sample.to_pickle(
        SHAP_SAMPLE_FILE,
        compression="gzip",
    )

    shap_sample.to_csv(
        SHAP_SAMPLE_PREVIEW_FILE,
        index=False,
        encoding="utf-8-sig",
    )

    print(
        f"Candidate rows: "
        f"{len(candidate_data):,}"
    )

    print(
        f"SHAP sample rows: "
        f"{len(shap_sample):,}"
    )

    print(
        "\nReference-abundance groups:"
    )

    print(
        shap_sample[
            "abundance_group"
        ]
        .value_counts()
        .to_string()
    )

    print(
        "\nShallow-detection groups:"
    )

    print(
        shap_sample[
            "shallow_detection_group"
        ]
        .value_counts()
        .to_string()
    )

    print(
        f"\nSaved: {SHAP_SAMPLE_FILE}"
    )

    print(
        f"Saved: {SHAP_SAMPLE_PREVIEW_FILE}"
    )

    # --------------------------------------------------------
    # Step 4: Random Forest SHAP
    # --------------------------------------------------------

    banner(
        "Step 4: Compute Random Forest SHAP values"
    )

    rf_start = time.time()

    (
        rf_shap_values,
        rf_base_values,
    ) = extract_rf_shap_values(
        rf_model,
        X_shap,
    )

    rf_shap_table = build_shap_table(
        metadata=shap_metadata,
        X=X_shap,
        shap_values=rf_shap_values,
        base_values=rf_base_values,
        model_name="Random Forest",
    )

    rf_shap_table.to_pickle(
        RF_SHAP_FILE,
        compression="gzip",
    )

    rf_shap_table.to_csv(
        RF_SHAP_PREVIEW_FILE,
        index=False,
        encoding="utf-8-sig",
    )

    print(
        "Random Forest SHAP matrix shape: "
        f"{rf_shap_values.shape}"
    )

    print(
        "Random Forest SHAP runtime: "
        f"{time.time() - rf_start:.2f} seconds"
    )

    print(
        f"Saved: {RF_SHAP_FILE}"
    )

    print(
        f"Saved: {RF_SHAP_PREVIEW_FILE}"
    )

    # --------------------------------------------------------
    # Step 5: XGBoost SHAP
    # --------------------------------------------------------

    banner(
        "Step 5: Compute XGBoost SHAP values"
    )

    xgb_start = time.time()

    (
        xgb_shap_values,
        xgb_base_values,
    ) = extract_xgb_shap_values(
        xgb_model,
        X_shap,
    )

    xgb_shap_table = build_shap_table(
        metadata=shap_metadata,
        X=X_shap,
        shap_values=xgb_shap_values,
        base_values=xgb_base_values,
        model_name="XGBoost",
    )

    xgb_shap_table.to_pickle(
        XGB_SHAP_FILE,
        compression="gzip",
    )

    xgb_shap_table.to_csv(
        XGB_SHAP_PREVIEW_FILE,
        index=False,
        encoding="utf-8-sig",
    )

    print(
        "XGBoost SHAP matrix shape: "
        f"{xgb_shap_values.shape}"
    )

    print(
        "XGBoost SHAP runtime: "
        f"{time.time() - xgb_start:.2f} seconds"
    )

    print(
        f"Saved: {XGB_SHAP_FILE}"
    )

    print(
        f"Saved: {XGB_SHAP_PREVIEW_FILE}"
    )

    # --------------------------------------------------------
    # Step 6: SHAP additivity check
    # --------------------------------------------------------

    banner(
        "Step 6: Check SHAP additivity"
    )

    additivity_check = (
        calculate_additivity_check(
            rf_model=rf_model,
            xgb_model=xgb_model,
            X=X_shap,
            rf_shap_values=(
                rf_shap_values
            ),
            rf_base_values=(
                rf_base_values
            ),
            xgb_shap_values=(
                xgb_shap_values
            ),
            xgb_base_values=(
                xgb_base_values
            ),
        )
    )

    additivity_check.to_csv(
        ADDITIVITY_FILE,
        index=False,
        encoding="utf-8-sig",
    )

    print(
        additivity_check.to_string(
            index=False
        )
    )

    print(
        f"\nSaved: {ADDITIVITY_FILE}"
    )

    # --------------------------------------------------------
    # Step 7: Save configuration
    # --------------------------------------------------------

    banner(
        "Step 7: Save SHAP computation settings"
    )

    config = {
        "random_forest_model_file": str(
            RF_MODEL_FILE
        ),
        "xgboost_model_file": str(
            XGB_MODEL_FILE
        ),
        "test_prediction_file": str(
            TEST_PREDICTION_FILE
        ),
        "shap_output_directory": str(
            SHAP_DIR
        ),
        "feature_columns": (
            FEATURE_COLUMNS
        ),
        "n_shap_rows_requested": (
            N_SHAP_ROWS
        ),
        "n_shap_rows_used": (
            n_shap_rows
        ),
        "exclude_other": (
            EXCLUDE_OTHER
        ),
        "random_state": (
            RANDOM_STATE
        ),
        "pseudocount": (
            PSEUDOCOUNT
        ),
        "shap_target": (
            "Pre-normalisation model output on "
            "the log10(reference_RA + 1e-8) scale."
        ),
        "interpretation_warning": (
            "SHAP values describe predictive associations. "
            "They do not establish ecological causality and "
            "do not directly explain the final within-sample "
            "normalised relative abundance."
        ),
    }

    with open(
        CONFIG_FILE,
        "w",
        encoding="utf-8",
    ) as file:
        json.dump(
            config,
            file,
            ensure_ascii=False,
            indent=2,
        )

    print(
        f"Saved: {CONFIG_FILE}"
    )

    # --------------------------------------------------------
    # Completion summary
    # --------------------------------------------------------

    banner(
        "SHAP computation completed successfully"
    )

    print(
        "Created files:"
    )

    output_files = [
        SHAP_SAMPLE_FILE,
        SHAP_SAMPLE_PREVIEW_FILE,
        RF_SHAP_FILE,
        RF_SHAP_PREVIEW_FILE,
        XGB_SHAP_FILE,
        XGB_SHAP_PREVIEW_FILE,
        ADDITIVITY_FILE,
        CONFIG_FILE,
    ]

    for file_path in output_files:
        try:
            relative_path = (
                file_path
                .relative_to(
                    SHAP_DIR.parent
                )
            )

            print(
                f"  - results/{relative_path}"
            )

        except ValueError:
            print(
                f"  - {file_path}"
            )

    print(
        "\nTotal runtime: "
        f"{(time.time() - overall_start) / 60:.2f} minutes"
    )


if __name__ == "__main__":
    main()